// NODO: Formatear Contexto de Aprendizaje (V2 - Anti-Bucle)

const allRows = $input.all();

// 1. Filtrar solo filas con "POSITIVO"
let rawEjemplos = allRows.filter(row => {
  const fb = row.json.feedback_humano;
  return fb && fb.toString().toUpperCase().includes('POSITIVO');
});

// 2. DEDUPLICAR EJEMPLOS
const uniqueExamplesMap = new Map();
rawEjemplos.forEach(item => {
    if (item.json.titulo) {
        uniqueExamplesMap.set(item.json.titulo, item);
    }
});
const ejemplosUnicos = Array.from(uniqueExamplesMap.values());

// 3. CASO VACÍO
if (ejemplosUnicos.length === 0) {
  return [{ json: { contexto_aprendizaje: "No hay ejemplos históricos disponibles. Usa la Matriz de Validación estándar." } }];
}

// 4. GENERAR TEXTO
let textoEntrenamiento = "He revisado el historial y encontré estos casos de éxito que debes imitar:\n";
const seleccion = ejemplosUnicos.slice(0, 3);

seleccion.forEach((e, i) => {
  const d = e.json;
  textoEntrenamiento += `
--- EJEMPLO MODELO #${i + 1} ---
Título: "${d.titulo}"
Razón Validación: "${d.validacion_razon}"
Clasificación Correcta: Horizonte ${d.horizonte} | Probabilidad ${d.probabilidad} | Relevancia ${d.relevancia}
----------------------------------
`;
});

textoEntrenamiento += "\nUsa la lógica de estos ejemplos para clasificar las nuevas noticias.";

return [{ json: { contexto_aprendizaje: textoEntrenamiento } }];

// PREPARAR TEXTO PARA MEMORIA VECTORIAL (Pinecone)
// Usa los campos del Format Final Columns (nombres reales de columnas)
const item = $input.first ? $input.first() : { json: $input.item.json };
const json = item.json;

const textoParaVector = [
  'EMPRESA: ' + (json['COMPANY NAME'] || ''),
  'PAÍS: ' + (json['PAÍS'] || ''),
  'LÍNEA: ' + (json['LÍNEA DE NEGOCIO'] || ''),
  'TIER: ' + (json['TIER'] || ''),
  'RADAR: ' + (json['RADAR ACTIVO SI/NO'] || 'No'),
  'TIPO SEÑAL: ' + (json['TIPO DE SEÑAL DE INVERSIÓN'] || ''),
  'DESCRIPCIÓN: ' + (json['DESCRIPCIÓN DE SEÑAL (RESUMEN)'] || ''),
  'FUENTE: ' + (json['FUENTE DE LA SEÑAL'] || ''),
  'SCORE: ' + (json['SCORE RADAR'] || 0),
  'FECHA: ' + (json['Fecha Escaneo'] || '')
].join('\n');

return {
  json: {
    ...json,
    pageContent: textoParaVector,
    empresa: json['COMPANY NAME'],
    pais: json['PAÍS'],
    descripcion: json['DESCRIPCIÓN DE SEÑAL (RESUMEN)'],
    titulo: (json['TIPO DE SEÑAL DE INVERSIÓN'] || '') + ' - ' + (json['COMPANY NAME'] || ''),
    validacion_razon: json['_qa_status'] || 'OK'
  }
};

// ═══ NORMALIZADOR MATEC v5.1 — Webhook (body.empresas) + Google Sheets ═══
// v5.1: Webhook N8N v2 envuelve el payload bajo la clave "body".
//       Extraemos con fallback: payload = primerItem.body || primerItem.

const items = $input.all();

// ── Funciones helper ───────────────────────────────────────────────────────
const clean = (v) => {
  if (v === null || v === undefined) return '';
  return String(v).trim().toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '');
};

const normalizarLinea = (lineaRaw, sectorRaw) => {
  const l = clean(lineaRaw || '');
  const s = clean(sectorRaw || '');
  if (l.includes('bhs') || l.includes('aeropuerto') || l.includes('airport') || l.includes('aviation')) return 'BHS';
  if (l.includes('carton') || l.includes('papel') || l.includes('corrugado') || l.includes('packaging')) return 'Carton';
  if (l.includes('intralog') || l.includes('logistic') || l.includes('distribucion') || l.includes('cedi') || l.includes('solumat')) return 'Intralogistica';
  if (s.includes('airlines') || s.includes('aviation') || s.includes('airport')) return 'BHS';
  if (s.includes('carton') || s.includes('papel') || s.includes('packaging') || s.includes('corrugado')) return 'Carton';
  if (s.includes('logistic') || s.includes('retail') || s.includes('automotive') || s.includes('ecommerce')) return 'Intralogistica';
  if (s.includes('epc') || s.includes('constructora') || s.includes('civil')) return 'BHS';
  return lineaRaw || 'General';
};

const buildTavilyQuery = (empresa, linea, pais) => {
  const a = '(2026 OR 2027 OR 2028)';
  if (linea === 'BHS')
    return (`"${empresa}" aeropuerto terminal CAPEX inversion licitacion concesion modernizacion ${pais} ${a}`).substring(0, 400);
  if (linea === 'Carton')
    return (`"${empresa}" CAPEX inversion planta corrugadora expansion carton ${pais} ${a}`).substring(0, 400);
  if (linea === 'Intralogistica')
    return (`"${empresa}" CAPEX inversion centro distribucion CEDI WMS automatizacion ${pais} ${a}`).substring(0, 400);
  return (`"${empresa}" CAPEX inversion licitacion expansion proyecto ${pais} ${a}`).substring(0, 400);
};

const buildQuery = (empresa, linea) => {
  const a = '(2026 OR 2027 OR 2028)';
  const baseInv = '(CAPEX OR "inversión" OR licitación OR expansión OR "nueva planta" OR "nueva terminal" OR concesión)';
  if (linea === 'BHS')
    return (`("${empresa}") AND (${baseInv} OR "BHS" OR "baggage handling" OR aeropuerto OR terminal OR CUTE OR CUSS OR "concesión aeroportuaria") AND ${a}`);
  if (linea === 'Carton')
    return (`"${empresa}" AND (${baseInv} OR corrugadora OR cartón OR packaging OR empaques OR "planta cartón") AND ${a}`);
  if (linea === 'Intralogistica')
    return (`"${empresa}" AND (${baseInv} OR CEDI OR WMS OR ASRS OR sorter OR conveyor OR picking OR intralogística OR "bodega automatizada") AND ${a}`);
  return (`"${empresa}" AND (${baseInv}) AND ${a}`);
};

// ── DETECCIÓN WEBHOOK v5.1 ────────────────────────────────────────────────────────────
// El Webhook node v2 de N8N envuelve el body bajo la clave "body".
// primerItem = { headers:{}, params:{}, query:{}, BODY:{empresas:[...],...}, webhookUrl, executionMode }
// Por eso debemos leer primerItem.body.empresas, no primerItem.empresas.
const primerItem = items[0]?.json || {};
const payload    = primerItem.body || primerItem; // fallback: si ya viene sin wrapping

const esWebhookConEmpresas = (
  items.length === 1 &&
  Array.isArray(payload.empresas) &&
  payload.empresas.length > 0
);

console.log('[CodeJS4-v5.1] items:', items.length, '| esWebhookConEmpresas:', esWebhookConEmpresas, '| empresas len:', (payload.empresas || []).length);

if (esWebhookConEmpresas) {
  // ── Path Webhook: transformar directamente al formato estándar ────────
  const lineaDefault = payload.linea || '';
  console.log('[CodeJS4-v5.1] Modo WEBHOOK — empresas recibidas:', payload.empresas.length);
  return payload.empresas.map(e => {
    const empresa  = e.nombre || e.company_name || '';
    const pais     = e.pais   || 'LATAM';
    const lineaRaw = e.linea  || e.linea_negocio || lineaDefault;
    const linea    = normalizarLinea(lineaRaw, '');
    return {
      json: {
        empresa,
        pais,
        linea_negocio:  linea,
        tier:           e.tier || 'Tier B',
        sector:         '',
        dominio:        e.dominio || e.company_domain || e.website || e.url || '',
        prioridad:      '',
        query:          buildQuery(empresa, linea),
        tavily_query:   buildTavilyQuery(empresa, linea, pais),
        source:         'webhook',
      }
    };
  });
}

// ── Path Google Sheets: lógica original de detección dinámica de headers ─────
console.log('[CodeJS4-v5.1] Modo GOOGLE SHEETS — items recibidos:', items.length);

const resultados = [];

// ─── PASO 1: Encontrar la fila que es el header real ───────────────────────
let headerRowIndex = -1;
let colMap = {};

const HEADER_SIGNAL = ['company name', 'nombre del operador', 'empresa foco', 'company'];

for (let i = 0; i < items.length; i++) {
  const d = items[i].json;
  const vals = Object.values(d);
  const keys = Object.keys(d);

  for (let j = 0; j < vals.length; j++) {
    if (HEADER_SIGNAL.includes(clean(vals[j]))) {
      headerRowIndex = i;
      vals.forEach((v, idx) => {
        if (v !== null && v !== undefined && String(v).trim() !== '') {
          colMap[keys[idx]] = String(v).trim();
        }
      });
      break;
    }
  }
  if (headerRowIndex >= 0) break;
}

if (headerRowIndex < 0) {
  for (let i = 0; i < Math.min(5, items.length); i++) {
    const keys = Object.keys(items[i].json);
    for (const k of keys) {
      if (HEADER_SIGNAL.includes(clean(k))) {
        headerRowIndex = i - 1;
        items.slice(i).forEach(it => {
          Object.keys(it.json).forEach(k => { colMap[k] = k; });
        });
        break;
      }
    }
    if (headerRowIndex >= 0) break;
  }
}

const getVal = (row, targetHeader) => {
  const t = clean(targetHeader);
  for (const [key, header] of Object.entries(colMap)) {
    if (clean(header) === t) {
      return row[key] !== undefined ? String(row[key]).trim() : '';
    }
  }
  for (const key of Object.keys(row)) {
    if (clean(key) === t) {
      return row[key] !== undefined ? String(row[key]).trim() : '';
    }
  }
  return '';
};

// ─── PASO 2: Procesar filas de datos ─────────────────────────────────────
const dataStart = Math.max(0, headerRowIndex + 1);
for (let i = dataStart; i < items.length; i++) {
  const d = items[i].json;

  const empresa = getVal(d, 'COMPANY NAME');
  if (!empresa || empresa === '' || clean(empresa) === 'company name') continue;
  if (empresa.startsWith('#') || empresa.toLowerCase().startsWith('total')) continue;

  const id        = getVal(d, 'ID') || String(i);
  const pais      = getVal(d, 'PAÍS') || getVal(d, 'PAIS') || 'LATAM';
  const lineaRaw  = getVal(d, 'LÍNEA DE NEGOCIO') || getVal(d, 'LINEA DE NEGOCIO') || '';
  const sector    = getVal(d, 'INDUSTRIA DEL CLIENTE') || getVal(d, 'INDSUTRIA DEL CLIENTE') || '';
  const tier      = getVal(d, 'TIER') || 'Sin Tier';
  const dominio   = getVal(d, 'DOMINIO') || '';
  const prioridad = getVal(d, 'PRIORIDAD COMERCIAL') || getVal(d, 'PRIORIDAD COMERCAL') || '';

  const linea_negocio = normalizarLinea(lineaRaw, sector);
  const query = buildQuery(empresa, linea_negocio);
  const tavily_query = buildTavilyQuery(empresa, linea_negocio, pais);

  resultados.push({ json: { id, empresa, pais, sector, linea_negocio, tier, dominio, prioridad, query, tavily_query, source: 'sheets' } });
}

if (resultados.length === 0) {
  return [{ json: {
    _debug: true,
    _error: 'No se encontraron clientes en el Sheet. Revisa la estructura.',
    headerRowIndex,
    colMapKeys: Object.values(colMap).slice(0, 20),
    firstItemKeys: Object.keys(items[0]?.json || {}).slice(0, 20),
    firstItemValues: Object.values(items[0]?.json || {}).slice(0, 20)
  }}];
}

return resultados;

// ═══ NORMALIZADOR + PRIORIDAD DE FUENTES v2 ═══
// Agrega latitude-15.com como fuente premium para línea BHS (aeropuertos LATAM)

const item = $input.item.json;
const raw = item.results || item.organic || [];

const DOMAIN_PRIORITY = {
  'bnamericas.com': 1000,
  'ijglobal.com': 900,
  // Gobierno Colombia
  'secop.gov.co': 820, 'aerocivil.gov.co': 820, 'mincit.gov.co': 810,
  'dnp.gov.co': 810, 'infraestructura.gov.co': 810, 'mintransporte.gov.co': 800,
  // Gobierno LATAM
  'ccr.com.br': 750, 'bndes.gov.br': 750, 'anac.gov.br': 740,
  'sat.gob.mx': 720, 'sct.gob.mx': 720, 'aeropuertos.gov.ar': 720,
  // ── NUEVA FUENTE BHS: Latitude-15 ──
  'latitude-15.com': 700,           // Aeropuertos e infraestructura LATAM — fuente nueva de Paola
  'airportscouncil.org': 680,       // ACI World — organismo aeroportuario global
  'aci-lac.aero': 680,              // ACI LATAM & Caribbean
  // Bolsas & organismos financieros
  'bolsadesantiago.com': 680, 'bmv.com.mx': 680, 'bvl.com.pe': 680,
  // Premium news / inversión
  'bloomberg.com': 620, 'reuters.com': 620, 'ft.com': 600,
  'constructiondive.com': 560, 'portafolio.co': 540,
  'eltiempo.com': 500, 'elcolombiano.com': 480,
  'semana.com': 460, 'dinero.com': 460,
  'infobae.com': 430, 'clarin.com': 400,
  'linkedin.com': 350,
  // Fuentes a deprioritizar (aviación genérica, no inversión)
  'aviationweek.com': -200, 'avweb.com': -200,
  'skybrary.aero': -300, 'airlineratings.com': -200,
  // Fuentes a ignorar
  'wikipedia.org': -500, 'reddit.com': -500, 'quora.com': -500,
};

const getDomainPriority = (url) => {
  if (!url) return 0;
  try {
    const hostname = new URL(url).hostname.replace('www.', '');
    if (DOMAIN_PRIORITY[hostname] !== undefined) return DOMAIN_PRIORITY[hostname];
    if (hostname.match(/\.gov\./) || hostname.endsWith('.gov')) return 760;
    for (const [domain, score] of Object.entries(DOMAIN_PRIORITY)) {
      if (hostname.includes(domain.split('.')[0])) return score;
    }
  } catch(e) {}
  return 0;
};

const normalizeItem = (r) => {
  const url = r.url || r.link || '';
  let domain = '';
  try { domain = new URL(url).hostname.replace('www.', ''); } catch(e) {}
  return {
    title: r.title || '',
    link: url,
    snippet: r.content ? r.content.substring(0, 500) : (r.snippet || ''),
    date: r.published_date || r.date || '',
    source: domain || r.source || '',
    score: r.score || 0,
    _domain_priority: getDomainPriority(url)
  };
};

const organic = raw
  .map(normalizeItem)
  .filter(r => r.link && r.title)
  .sort((a, b) => {
    const scoreA = (a._domain_priority * 0.7) + (a.score * 300);
    const scoreB = (b._domain_priority * 0.7) + (b.score * 300);
    return scoreB - scoreA;
  })
  .slice(0, 10);

return {
  ...item,
  organic,
  tavily_answer: item.answer || ''
};

// ═══ VALIDADOR DE FUENTES — Checks determinísticos ═══
// Verifica si la señal tiene respaldo real antes de llamar al AI Validador.
// Referencia los organic[] de Tavily para confirmar URLs y convergencia.

const output = $json.output || $json;
const organic = $('Code in JavaScript5').item.json.organic || [];

const PREMIUM_DOMAINS = [
  'bnamericas.com', 'secop.gov.co', 'aerocivil.gov.co', 'anac.gob.ar',
  'mincit.gov.co', 'dnp.gov.co', 'infraestructura.gov.co', 'ccr.com.br',
  'linkedin.com', 'bolsadesantiago.com', 'bmv.com.mx', 'bvl.com.pe',
  'aeroportos.gov.br', 'caasd.gov.do', 'dgac.gob.cl', 'iaac.int',
  'aena.es', 'bndes.gov.br', 'iata.org', 'aci.aero'
];

const INVERSION_KEYWORDS = [
  'capex', 'invers', 'construc', 'licitaci', 'ampliac',
  'modernizac', 'proyecto', 'terminal', 'planta', 'cedi',
  'expansion', 'contrat', 'adjudic', 'concesion', 'habilitac'
];

const COMPLETED_WORDS = [
  'inauguro', 'inaugurado', 'fue entregado', 'ya opera',
  'abrio sus puertas', 'fue completado', 'termino su construccion',
  'finalizo', 'en operacion desde', 'fue inaugurado', 'completado'
];

const normalize = s => String(s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const radarActivo = output?.radar_activo === 'Sí' || output?.radar_activo === 'Si';
const fuenteLink = normalize(output?.fuente_link || '');
const empresaNorm = normalize(output?.empresa_evaluada || '').substring(0, 25);

// ─── Sin señal: auto-aprobado ─────────��──────────────────────────
if (!radarActivo) {
  return [{
    json: {
      ...output,
      _val_precheck: 'Auto-Aprobado',
      _val_motivo: 'Sin señal activa — validación no requerida',
      _url_verificada: false,
      _fuente_premium: false,
      _convergencia: 0
    }
  }];
}

// ─���� Checks para señales positivas ─────────────────────────────
// 1. ¿La URL reportada existe en los resultados de Tavily?
const organicUrls = organic.map(r => normalize(r.link || ''));
const fuenteIs40  = fuenteLink.substring(0, 40);
const urlVerificada = fuenteLink !== 'no disponible' &&
  fuenteLink.startsWith('http') &&
  organicUrls.some(u => u.includes(fuenteIs40));

// 2. ��El dominio es premium/oficial?
let fuente_premium = false;
try {
  const url = new URL(output.fuente_link || '');
  const domain = url.hostname.replace('www.', '');
  fuente_premium = PREMIUM_DOMAINS.some(d => domain.includes(d));
} catch(e) {}

// 3. ¿Cuántos snippets mencionan la empresa + keywords de inversión?
const convergencia = organic.filter(r => {
  const text = normalize((r.snippet || '') + ' ' + (r.title || ''));
  return text.includes(empresaNorm.substring(0, 15)) &&
    INVERSION_KEYWORDS.some(k => text.includes(k));
}).length;

// 4. ¿Algún snippet menciona proyecto completado?
const proyectoCompletado = organic.some(r => {
  const text = normalize((r.snippet || '') + ' ' + (r.title || ''));
  return COMPLETED_WORDS.some(w => text.includes(w));
});

// 5. ¿URL claramente inventada?
const urlInventada = fuenteLink !== 'no disponible' &&
  fuenteLink.startsWith('http') &&
  !urlVerificada;

// ─── Clasificación ───────────────────────────────────────────────
let _val_precheck, _val_motivo;

if (proyectoCompletado) {
  _val_precheck = 'Observado';
  _val_motivo   = 'Snippets sugieren proyecto ya completado o inaugurado';
} else if (urlInventada) {
  _val_precheck = 'Observado';
  _val_motivo   = `URL no encontrada en resultados Tavily: ${output.fuente_link}`;
} else if (fuente_premium && convergencia >= 1) {
  _val_precheck = 'Aprobado';
  _val_motivo   = `Fuente premium (${output.fuente_nombre || 'oficial'}) + ${convergencia} snippet(s) confirmando`;
} else if (convergencia >= 2) {
  _val_precheck = 'Aprobado';
  _val_motivo   = `${convergencia} snippets independientes confirman la inversión`;
} else if (urlVerificada && convergencia >= 1) {
  _val_precheck = 'Aprobado';
  _val_motivo   = 'URL verificada en organic[] + al menos 1 snippet relevante';
} else if (fuenteLink === 'no disponible') {
  _val_precheck = 'Borderline';
  _val_motivo   = 'Sin URL reportada — enviando a validación IA para revisar snippets';
} else {
  _val_precheck = 'Borderline';
  _val_motivo   = `Fuente no premium, convergencia baja (${convergencia}) — enviando a validación IA`;
}

return [{
  json: {
    ...output,
    _val_precheck,
    _val_motivo,
    _url_verificada: urlVerificada,
    _fuente_premium: fuente_premium,
    _convergencia: convergencia,
    _proyecto_completado: proyectoCompletado
  }
}];

