// ═══ FUSIONAR RESULTADO DE VALIDACIÓN ═══
// Combina la conclusión del AI Validador con los datos del radar original.
// Output: objeto plano con todos los campos para el If de routing.

const radarData = $('AI Agent RADAR1').item.json.output || {};
const valData   = $json.output || $json; // Resultado del AI Agente Validador
const preData   = $('Validador de Fuentes1').item.json;

return [{
  json: {
    // Campos del radar (base)
    ...radarData,
    // Pre-check determinístico
    _val_precheck:       preData._val_precheck || 'Borderline',
    _val_motivo_codigo:  preData._val_motivo   || '',
    _url_verificada:     preData._url_verificada || false,
    _fuente_premium:     preData._fuente_premium || false,
