// ── Funciones helper ───────────────────────────────────────────────────────
const clean = (v) => {
  if (v === null || v === undefined) return '';
  return String(v).trim().toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '');
};

const normalizarLinea = (lineaRaw, sectorRaw) => {
  const l = clean(lineaRaw || '');
  const s = clean(sectorRaw || '');
  if (l.includes('bhs') || l.includes('aeropuerto') || l.includes('airport') || l.includes('aviation')) return 'BHS';
  if (l.includes('carton') || l.includes('papel') || l.includes('corrugado') || l.includes('packaging')) return 'Carton';
  if (l.includes('intralog') || l.includes('logistic') || l.includes('distribucion') || l.includes('cedi') || l.includes('solumat')) return 'Intralogistica';
  if (s.includes('airlines') || s.includes('aviation') || s.includes('airport')) return 'BHS';
  if (s.includes('carton') || s.includes('papel') || s.includes('packaging') || s.includes('corrugado')) return 'Carton';
  if (s.includes('logistic') || s.includes('retail') || s.includes('automotive') || s.includes('ecommerce')) return 'Intralogistica';
  if (s.includes('epc') || s.includes('constructora') || s.includes('civil')) return 'BHS';
  return lineaRaw || 'General';
};

const buildTavilyQuery = (empresa, linea, pais) => {
  const a = '(2026 OR 2027 OR 2028)';
  if (linea === 'BHS')
    return (`"${empresa}" aeropuerto terminal CAPEX inversion licitacion concesion modernizacion ${pais} ${a}`).substring(0, 400);
  if (linea === 'Carton')
    return (`"${empresa}" CAPEX inversion planta corrugadora expansion carton ${pais} ${a}`).substring(0, 400);
  if (linea === 'Intralogistica')
    return (`"${empresa}" CAPEX inversion centro distribucion CEDI WMS automatizacion ${pais} ${a}`).substring(0, 400);
  return (`"${empresa}" CAPEX inversion licitacion expansion proyecto ${pais} ${a}`).substring(0, 400);
};

const buildQuery = (empresa, linea) => {
  const a = '(2026 OR 2027 OR 2028)';
  const baseInv = '(CAPEX OR "inversión" OR licitación OR expansión OR "nueva planta" OR "nueva terminal" OR concesión)';
  if (linea === 'BHS')
    return (`("${empresa}") AND (${baseInv} OR "BHS" OR "baggage handling" OR aeropuerto OR terminal OR CUTE OR CUSS OR "concesión aeroportuaria") AND ${a}`);
  if (linea === 'Carton')
    return (`"${empresa}" AND (${baseInv} OR corrugadora OR cartón OR packaging OR empaques OR "planta cartón") AND ${a}`);
  if (linea === 'Intralogistica')
    return (`"${empresa}" AND (${baseInv} OR CEDI OR WMS OR ASRS OR sorter OR conveyor OR picking OR intralogística OR "bodega automatizada") AND ${a}`);
  return (`"${empresa}" AND (${baseInv}) AND ${a}`);
};

