// ── Path Google Sheets: lógica original de detección dinámica de headers ─────
console.log('[CodeJS4-v5.1] Modo GOOGLE SHEETS — items recibidos:', items.length);

const resultados = [];

// ─── PASO 1: Encontrar la fila que es el header real ───────────────────────
let headerRowIndex = -1;
let colMap = {};

const HEADER_SIGNAL = ['company name', 'nombre del operador', 'empresa foco', 'company'];

for (let i = 0; i < items.length; i++) {
  const d = items[i].json;
  const vals = Object.values(d);
  const keys = Object.keys(d);

  for (let j = 0; j < vals.length; j++) {
    if (HEADER_SIGNAL.includes(clean(vals[j]))) {
      headerRowIndex = i;
      vals.forEach((v, idx) => {
        if (v !== null && v !== undefined && String(v).trim() !== '') {
          colMap[keys[idx]] = String(v).trim();
        }
      });
      break;
    }
  }
  if (headerRowIndex >= 0) break;
}

if (headerRowIndex < 0) {
  for (let i = 0; i < Math.min(5, items.length); i++) {
    const keys = Object.keys(items[i].json);
    for (const k of keys) {
      if (HEADER_SIGNAL.includes(clean(k))) {
        headerRowIndex = i - 1;
        items.slice(i).forEach(it => {
          Object.keys(it.json).forEach(k => { colMap[k] = k; });
        });
        break;
      }
    }
    if (headerRowIndex >= 0) break;
  }
}

const getVal = (row, targetHeader) => {
  const t = clean(targetHeader);
  for (const [key, header] of Object.entries(colMap)) {
    if (clean(header) === t) {
      return row[key] !== undefined ? String(row[key]).trim() : '';
    }
  }
  for (const key of Object.keys(row)) {
    if (clean(key) === t) {
      return row[key] !== undefined ? String(row[key]).trim() : '';
    }
  }
  return '';
};

// ─── PASO 2: Procesar filas de datos ─────────────────────────────────────
const dataStart = Math.max(0, headerRowIndex + 1);
for (let i = dataStart; i < items.length; i++) {
  const d = items[i].json;

  const empresa = getVal(d, 'COMPANY NAME');
  if (!empresa || empresa === '' || clean(empresa) === 'company name') continue;
  if (empresa.startsWith('#') || empresa.toLowerCase().startsWith('total')) continue;

  const id        = getVal(d, 'ID') || String(i);
  const pais      = getVal(d, 'PAÍS') || getVal(d, 'PAIS') || 'LATAM';
  const lineaRaw  = getVal(d, 'LÍNEA DE NEGOCIO') || getVal(d, 'LINEA DE NEGOCIO') || '';
  const sector    = getVal(d, 'INDUSTRIA DEL CLIENTE') || getVal(d, 'INDSUTRIA DEL CLIENTE') || '';
  const tier      = getVal(d, 'TIER') || 'Sin Tier';
  const dominio   = getVal(d, 'DOMINIO') || '';
  const prioridad = getVal(d, 'PRIORIDAD COMERCIAL') || getVal(d, 'PRIORIDAD COMERCAL') || '';

  const linea_negocio = normalizarLinea(lineaRaw, sector);
  const query = buildQuery(empresa, linea_negocio);
  const tavily_query = buildTavilyQuery(empresa, linea_negocio, pais);

  resultados.push({ json: { id, empresa, pais, sector, linea_negocio, tier, dominio, prioridad, query, tavily_query, source: 'sheets' } });
}

if (resultados.length === 0) {
  return [{ json: {
    _debug: true,
    _error: 'No se encontraron clientes en el Sheet. Revisa la estructura.',
    headerRowIndex,
    colMapKeys: Object.values(colMap).slice(0, 20),
    firstItemKeys: Object.keys(items[0]?.json || {}).slice(0, 20),
    firstItemValues: Object.values(items[0]?.json || {}).slice(0, 20)
  }}];
}

