  'inauguro', 'inaugurado', 'fue entregado', 'ya opera',
  'abrio sus puertas', 'fue completado', 'termino su construccion',
  'finalizo', 'en operacion desde', 'fue inaugurado', 'completado'
];

const normalize = s => String(s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const radarActivo = output?.radar_activo === 'Sí' || output?.radar_activo === 'Si';
const fuenteLink = normalize(output?.fuente_link || '');
const empresaNorm = normalize(output?.empresa_evaluada || '').substring(0, 25);

// ─── Sin señal: auto-aprobado ─────────��──────────────────────────
if (!radarActivo) {
  return [{
    json: {
      ...output,
      _val_precheck: 'Auto-Aprobado',
      _val_motivo: 'Sin señal activa — validación no requerida',
      _url_verificada: false,
      _fuente_premium: false,
      _convergencia: 0
    }
  }];
}

// ─���� Checks para señales positivas ─────────────────────────────
// 1. ¿La URL reportada existe en los resultados de Tavily?
const organicUrls = organic.map(r => normalize(r.link || ''));
const fuenteIs40  = fuenteLink.substring(0, 40);
const urlVerificada = fuenteLink !== 'no disponible' &&
  fuenteLink.startsWith('http') &&
  organicUrls.some(u => u.includes(fuenteIs40));

// 2. ��El dominio es premium/oficial?
let fuente_premium = false;
try {
  const url = new URL(output.fuente_link || '');
  const domain = url.hostname.replace('www.', '');
  fuente_premium = PREMIUM_DOMAINS.some(d => domain.includes(d));
} catch(e) {}

// 3. ¿Cuántos snippets mencionan la empresa + keywords de inversión?
const convergencia = organic.filter(r => {
  const text = normalize((r.snippet || '') + ' ' + (r.title || ''));
  return text.includes(empresaNorm.substring(0, 15)) &&
    INVERSION_KEYWORDS.some(k => text.includes(k));
}).length;

// 4. ¿Algún snippet menciona proyecto completado?
const proyectoCompletado = organic.some(r => {
  const text = normalize((r.snippet || '') + ' ' + (r.title || ''));
  return COMPLETED_WORDS.some(w => text.includes(w));
});

// 5. ¿URL claramente inventada?
const urlInventada = fuenteLink !== 'no disponible' &&
  fuenteLink.startsWith('http') &&
  !urlVerificada;

// ─── Clasificación ───────────────────────────────────────────────
let _val_precheck, _val_motivo;

if (proyectoCompletado) {
  _val_precheck = 'Observado';
  _val_motivo   = 'Snippets sugieren proyecto ya completado o inaugurado';
} else if (urlInventada) {
  _val_precheck = 'Observado';
  _val_motivo   = `URL no encontrada en resultados Tavily: ${output.fuente_link}`;
} else if (fuente_premium && convergencia >= 1) {
  _val_precheck = 'Aprobado';
  _val_motivo   = `Fuente premium (${output.fuente_nombre || 'oficial'}) + ${convergencia} snippet(s) confirmando`;
} else if (convergencia >= 2) {
  _val_precheck = 'Aprobado';
  _val_motivo   = `${convergencia} snippets independientes confirman la inversión`;
} else if (urlVerificada && convergencia >= 1) {
  _val_precheck = 'Aprobado';
  _val_motivo   = 'URL verificada en organic[] + al menos 1 snippet relevante';
} else if (fuenteLink === 'no disponible') {
  _val_precheck = 'Borderline';
  _val_motivo   = 'Sin URL reportada — enviando a validación IA para revisar snippets';
} else {
  _val_precheck = 'Borderline';
  _val_motivo   = `Fuente no premium, convergencia baja (${convergencia}) — enviando a validación IA`;
}

return [{
  json: {
    ...output,
    _val_precheck,
    _val_motivo,
    _url_verificada: urlVerificada,
    _fuente_premium: fuente_premium,
    _convergencia: convergencia,
    _proyecto_completado: proyectoCompletado
  }
}];

