// ═══ FUSIONAR RESULTADO DE VALIDACIÓN ═══
// Combina la conclusión del AI Validador con los datos del radar original.
// Output: objeto plano con todos los campos para el If de routing.

const radarData = $('AI Agent RADAR1').item.json.output || {};
const valData   = $json.output || $json; // Resultado del AI Agente Validador
const preData   = $('Validador de Fuentes1').item.json;

return [{
  json: {
    // Campos del radar (base)
    ...radarData,
    // Pre-check determinístico
    _val_precheck:       preData._val_precheck || 'Borderline',
    _val_motivo_codigo:  preData._val_motivo   || '',
    _url_verificada:     preData._url_verificada || false,
    _fuente_premium:     preData._fuente_premium || false,
    _convergencia:       preData._convergencia   || 0,
    // Resultado de la validación IA
    validacion_estado:   valData.validacion_estado   || 'Observado',
    motivo_validacion:   valData.motivo_validacion   || '',
    links_validados:     JSON.stringify(valData.links_validados || []),
    links_rechazados:    JSON.stringify(valData.links_rechazados || []),
    confianza:           valData.confianza            || 'Baja',
    convergencia_count:  valData.convergencia_count   || 0
  }
}];

// ═══ FUSIONAR BÚSQUEDAS: Primarias + General ═══
// Etapa 1 (BNAmericas / Gov) llega desde 'Buscar Fuentes Primarias1'
// Etapa 2 (General)          llega desde el nodo actual ($json)

const primarias  = $('Buscar Fuentes Primarias1').item.json.results || [];
const generales  = $input.item.json.results || [];
const answerGen  = $input.item.json.answer || '';

// Normalizar un resultado de Tavily a formato estándar
const normalize = (r, stage) => {
  const url = r.url || r.link || '';
  let domain = '';
  try { domain = new URL(url).hostname.replace('www.', ''); } catch(e) {}
  return {
    title:   r.title   || '',
    link:    url,
    snippet: (r.content || r.snippet || '').substring(0, 500),
    date:    r.published_date || r.date || '',
    source:  domain,
    score:   r.score || 0,
    _stage:  stage   // 'primaria' | 'general'
  };
};

// Combinar: Primarias primero, General después
const seenUrls = new Set();
const combined = [
  ...primarias.map(r => normalize(r, 'primaria')),
  ...generales.map(r => normalize(r, 'general'))
].filter(r => {
  if (!r.link || !r.title) return false;
  if (seenUrls.has(r.link)) return false;
  seenUrls.add(r.link);
  return true;
});

// Pasar al siguiente nodo con el formato esperado por Code JS5
return {
  ...$('Loop Over Items1').item.json,  // empresa, pais, linea, tier, tavily_query, etc.
  results: combined,
  answer: answerGen,
  _primarias_count: primarias.length,
  _generales_count: generales.length
};

// ═══ SORT + ROTACIÓN POR LÍNEA — v9.2 (Webhook bypass + Google Sheets) ═══
// v9.2: Si los items vienen del webhook (source='webhook'), ya están en el
// formato correcto con empresa, tavily_query, etc. → retornar sin filtro de día.
// Si vienen de Google Sheets → aplicar rotación/sort normal.

const clientes = $input.all();

// ── BYPASS WEBHOOK: empresas ya seleccionadas por el usuario ─────────────────
if (clientes.length > 0 && clientes[0].json.source === 'webhook') {
  console.log('[CodeJS1] Modo WEBHOOK — pasando', clientes.length, 'empresas sin filtro de rotación');
  return clientes.map(c => ({
    json: {
      ...c.json,
      _rotacion_linea: c.json.linea_negocio || 'WEBHOOK',
      _rotacion_modo:  'WEBHOOK — empresas seleccionadas desde el frontend',
      _rotacion_dia:   'N/A',
    }
  }));
}

// ── GOOGLE SHEETS PATH: Rotación por día de la semana ────────────────────────
const BATCH_SIZE = 5; // Schedule: 5 empresas por ejecución

const tierOrder = (item) => {
  const t = (item.json.tier || '').toString().toUpperCase().replace(/\s/g,'');
  if (t === 'TIERA')         return 0;
  if (t === 'TIERB-ALTA')    return 1;
  if (t === 'TIERB' || t === 'TIERB-BAJA') return 2;
  if (t === 'TIERC')         return 3;
  if (t === 'TIERD')         return 4;
  return 99;
};

const dayOfWeek = new Date().getDay();
const lineaPorDia = {
  0: null,                // Domingo: solo Tier A (todas las líneas)
  1: 'BHS',              // Lunes
  2: 'Carton',           // Martes
  3: 'Intralogistica',   // Miércoles
  4: 'BHS',              // Jueves
  5: 'Carton',           // Viernes
  6: 'Intralogistica',   // Sábado
};

const lineaHoy = lineaPorDia[dayOfWeek];

let seleccionados = [...clientes].sort((a, b) => tierOrder(a) - tierOrder(b));
let modoUsado = '';

if (lineaHoy === null) {
  seleccionados = seleccionados.filter(c =>
    (c.json.tier || '').toUpperCase().replace(/\s/g,'') === 'TIERA'
  );
  modoUsado = 'DOMINGO — Tier A todas las líneas';
} else {
  const candidatos = seleccionados.filter(c => {
    const linea = (c.json.linea_negocio || '').toLowerCase().replace(/[^a-z]/g, '');
    const target = lineaHoy.toLowerCase();
    if (lineaHoy === 'Intralogistica') {
      return linea.includes('intralog') || linea.includes('solumat');
    }
    return linea.includes(target);
  });

  if (candidatos.length > 0) {
    seleccionados = candidatos;
    modoUsado = lineaHoy + ' — ' + candidatos.length + ' empresas en sheet';
  } else {
    // FALLBACK: línea del día sin empresas → usar todas por tier
    modoUsado = 'FALLBACK (sin ' + lineaHoy + ') — todas por tier';
  }
}

const dias = ['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'];
return seleccionados.slice(0, BATCH_SIZE).map(c => ({
  json: {
    ...c.json,
    _rotacion_linea: lineaHoy || 'TODAS',
    _rotacion_modo:  modoUsado,
    _rotacion_dia:   dias[dayOfWeek],
  }
}));

// Normalizar Linea v2 — detecta la linea de negocio con NFD normalization
// FIX: el regex [^A-Za-z] no maneja acentos correctamente sin NFD.
//   "LÍNEA DE NEGOCIO" → LNEADENEGOCIO (Í descartada) → no match.
//   Con NFD: "LI\u0301NEA..." → acento removido → LINEADENEGOCIO → match correcto.

// Función para normalizar una clave a ASCII
const normKey = k =>
  k.normalize('NFD')
   .replace(/[\u0300-\u036f]/g, '')  // quitar combining marks
   .replace(/[^A-Za-z]/g, '')           // quitar no-letras
   .toUpperCase();

// Buscar la clave que corresponde a Línea de Negocio
// Acepta: 'LÍNEA DE NEGOCIO', 'linea_negocio', 'LINEA DE NEGOCIO', etc.
const lineaKey = Object.keys($json).find(k => {
  const n = normKey(k);
  return n === 'LINEADENEGOCIO' || n === 'LINEANEGOCIO';
});

const rawLinea = lineaKey ? String($json[lineaKey]) : '';

console.log('[NormLinea-v2] lineaKey:', lineaKey, '| rawLinea:', rawLinea);

let _linea;
if (rawLinea.toUpperCase().includes('BHS')) {
  _linea = 'BHS';
} else if (rawLinea.normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^A-Za-z]/g,'').toUpperCase().includes('CART')) {
  _linea = 'Carton';
} else if (rawLinea.normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^A-Za-z]/g,'').toUpperCase().includes('INTRA')) {
  _linea = 'Intra';
} else {
  _linea = 'Intra'; // fallback
}

console.log('[NormLinea-v2] _linea:', _linea);

return { json: { ...$json, _linea } };
